const go=document.getElementById('bf-go'), out=document.getElementById('bf-out');
function render(){
  const a=+document.getElementById('bf-a').value|0;
  const b=+document.getElementById('bf-b').value|0;
  const c=+document.getElementById('bf-c').value|0;
  const d=+document.getElementById('bf-d').value|0;
  const L=a*a+b*b, R=c*c+d*d;
  const p=a*c+b*d, q=a*d-b*c;
  const P=Math.abs(p), Q=Math.abs(q);
  const check = P*P+Q*Q;
  out.textContent =
    `(${a}² + ${b}²) · (${c}² + ${d}²) = ${L} · ${R} = ${L*R}\n`+
    `                       = (${a}·${c} + ${b}·${d})² + (${a}·${d} - ${b}·${c})²\n`+
    `                       = ${P}² + ${Q}² = ${check}  ${check===L*R?'✓':'(mismatch)'}`;
}
go.addEventListener('click', render);
render();

