const svg = document.getElementById('lat-svg');
const pick = document.getElementById('lat-p');
const info = document.getElementById('lat-info');
const W=620, H=460, cx=W/2, cy=H/2;
const unit=36;  // pixels per lattice step
function render(){
  while(svg.firstChild) svg.removeChild(svg.firstChild);
  // axes
  svg.appendChild(SVG('line',{x1:0,y1:cy,x2:W,y2:cy,stroke:'var(--line)','stroke-width':1}));
  svg.appendChild(SVG('line',{x1:cx,y1:0,x2:cx,y2:H,stroke:'var(--line)','stroke-width':1}));
  // axis labels
  const tx = SVG('text',{x:W-10,y:cy-6,'text-anchor':'end','font-size':12,fill:'var(--mute)'});
  tx.textContent='Re'; svg.appendChild(tx);
  const ty = SVG('text',{x:cx+8,y:14,'text-anchor':'start','font-size':12,fill:'var(--mute)'});
  ty.textContent='Im'; svg.appendChild(ty);

  const p = +pick.value;
  // circle |α|²=p
  const R = unit*Math.sqrt(p);
  const col = (p===2)?'var(--pink)' : ((p%4===1)?'var(--green)':'var(--yellow)');
  svg.appendChild(SVG('circle',{cx,cy,r:R,fill:'none',stroke:col,'stroke-width':1.8,'stroke-dasharray':'4 3'}));
  // lattice points
  const xmax = Math.floor((W-cx)/unit), ymax = Math.floor((H-cy)/unit);
  const hits = [];
  for(let a=-xmax-1;a<=xmax+1;a++){
    for(let b=-ymax-1;b<=ymax+1;b++){
      const x = cx + a*unit, y = cy - b*unit;
      if(x<-2||x>W+2||y<-2||y>H+2) continue;
      const onCircle = (a*a+b*b===p);
      const r = onCircle?5:2.2;
      const fill = onCircle? col : 'var(--mute)';
      svg.appendChild(SVG('circle',{cx:x,cy:y,r,fill}));
      if(onCircle && !(a===0&&b===0)) hits.push([a,b]);
    }
  }
  // origin
  svg.appendChild(SVG('circle',{cx,cy,r:3,fill:'var(--blue)'}));
  // annotate hits (unique up to ±) with labels
  const labeled = new Set();
  for(const [a,b] of hits){
    const key = Math.abs(a)+':'+Math.abs(b);
    if(labeled.has(key)) continue;
    labeled.add(key);
    if(a<0||(a===0&&b<0)) continue;
    const x = cx + a*unit, y = cy - b*unit;
    const t = SVG('text',{x:x+9,y:y-6,'font-size':12,fill:col});
    t.textContent = `${a}${b>=0?'+':''}${b}i`;
    svg.appendChild(t);
  }
  const kind = (p===2)?'ramified, (2)=(1+i)²·(-i)'
             : (p%4===1)?`split, (${p})=(a+bi)(a-bi) with ${p}=${hits.length?Math.abs(hits[0][0]):'?'}²+${hits.length?Math.abs(hits[0][1]):'?'}²`
             : `inert (no lattice points on circle): ${p}≡3 (mod 4)`;
  info.textContent = kind;
}
pick.addEventListener('change', render);
render();

