pick.addEventListener('change', render);
render();

function factor(n){
  const f={}; let m=n;
  for(let p=2;p*p<=m;p++){
    while(m%p===0){ f[p]=(f[p]||0)+1; m/=p; }
  }
  if(m>1) f[m]=(f[m]||0)+1;
  return f;
}
function r2(n){
  if(n===0) return 1;
  let c=0;
  const s=Math.floor(Math.sqrt(n));
  for(let a=-s;a<=s;a++){
    const r=n-a*a; if(r<0) continue;
    const b=Math.round(Math.sqrt(r));
    if(b*b===r) c++;
  }
  return c;
}
function divs(n){
  const ds=[]; for(let d=1;d*d<=n;d++) if(n%d===0){ ds.push(d); if(d!==n/d) ds.push(n/d); }
  return ds.sort((a,b)=>a-b);
}
function oneRep(n){
  if(n===0) return '0²+0²';
  const s=Math.floor(Math.sqrt(n));
  for(let a=0;a<=s;a++){
    const r=n-a*a; if(r<0) break;
    const b=Math.round(Math.sqrt(r));
    if(b>=a && b*b===r) return `${a}² + ${b}²`;
  }
  return null;
}
const go=document.getElementById('ts-go'), out=document.getElementById('ts-out');
function render(){
  const n = Math.max(1,Math.min(10000, +document.getElementById('ts-n').value|0));
  const f = factor(n);
  const bad = [];
  const parts = [];
  for(const p of Object.keys(f).map(Number).sort((a,b)=>a-b)){
    const e = f[p];
    const tag = (p===2)?'[ram]' : (p%4===1?'[split]':'[inert]');
    if(p%4===3 && e%2===1) bad.push(p);
    parts.push(`${p}^${e} ${tag}`);
  }
  const ok = bad.length===0;
  const rep = ok ? oneRep(n) : null;
  const ds = divs(n);
  const d1 = ds.filter(d=>d%4===1).length;
  const d3 = ds.filter(d=>d%4===3).length;
  const jac = 4*(d1-d3);
  out.textContent =
    `n = ${n}\n`+
    `factorisation: ${parts.join(' · ')}\n`+
    (ok
      ? `YES — sum of two squares.  one rep: ${n} = ${rep}\n`+
        `Jacobi: r₂(${n}) = 4·(d₁−d₃) = 4·(${d1}−${d3}) = ${jac}  (brute: r₂=${r2(n)})`
      : `NO — bad primes (≡3 mod 4, odd exponent): ${bad.join(', ')}\n`+
        `Jacobi: r₂(${n}) = 4·(${d1}−${d3}) = ${jac}`);
}
go.addEventListener('click', render);
document.getElementById('ts-n').addEventListener('keypress', e=>{ if(e.key==='Enter') render(); });
render();

