function isExcluded(n){
  if(n<=0) return false;
  let m=n;
  while(m%4===0) m/=4;
  return m%8===7;
}
function r3(n){
  if(n===0) return 1;
  let c=0; const s=Math.floor(Math.sqrt(n));
  for(let a=-s;a<=s;a++)
    for(let b=-s;b<=s;b++){
      const r=n-a*a-b*b; if(r<0) continue;
      const cc=Math.round(Math.sqrt(r));
      if(cc*cc===r) c+=(cc===0?1:2);
    }
  return c;
}
function oneRep3(n){
  if(n===0) return '0²+0²+0²';
  const s=Math.floor(Math.sqrt(n));
  for(let a=0;a<=s;a++) for(let b=a;b<=s;b++){
    const r=n-a*a-b*b; if(r<0) break;
    const c=Math.round(Math.sqrt(r));
    if(c>=b && c*c===r) return `${a}² + ${b}² + ${c}²`;
  }
  return null;
}
// draw number line 0..200, mark excluded red, others small tick
const svg = document.getElementById('three-svg');
const W=620, H=160;
const N=200;
const xof = n => 20 + (n/N)*(W-40);
const yLine = 100;
// line
svg.appendChild(SVG('line',{x1:20,y1:yLine,x2:W-20,y2:yLine,stroke:'var(--line)','stroke-width':1.5}));
// ticks every 20
for(let n=0;n<=N;n+=20){
  svg.appendChild(SVG('line',{x1:xof(n),y1:yLine-5,x2:xof(n),y2:yLine+5,stroke:'var(--mute)','stroke-width':1}));
  const t = SVG('text',{x:xof(n),y:yLine+22,'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
  t.textContent = n; svg.appendChild(t);
}
// excluded marks
for(let n=0;n<=N;n++){
  if(isExcluded(n)){
    svg.appendChild(SVG('circle',{cx:xof(n),cy:yLine-14,r:4,fill:'var(--pink)'}));
    const t = SVG('text',{x:xof(n),y:yLine-22,'text-anchor':'middle','font-size':10,fill:'var(--pink)'});
    t.textContent = n;
    svg.appendChild(t);
  } else if(n>0){
    svg.appendChild(SVG('circle',{cx:xof(n),cy:yLine-8,r:1.6,fill:'var(--green)'}));
  }
}
// title
const lbl = SVG('text',{x:20,y:30,'font-size':13,fill:'var(--mute)'});
lbl.textContent = 'Red: excluded (of form 4ᵃ(8b+7)).  Green dots: sums of three squares.';
svg.appendChild(lbl);

const go=document.getElementById('th-go'), out=document.getElementById('th-out');
function render(){
  const n = Math.max(0, Math.min(2000, +document.getElementById('th-n').value|0));
  const ex = isExcluded(n);
  if(ex){
    let m=n, a=0; while(m%4===0){ m/=4; a++; }
    const b = (m-7)/8;
    out.textContent = `n = ${n} = 4^${a}·(8·${b}+7) — EXCLUDED\nr₃(${n}) = 0.`;
  } else {
    const rep = oneRep3(n);
    out.textContent = `n = ${n} — NOT of form 4ᵃ(8b+7)\none rep: ${n} = ${rep}\nr₃(${n}) = ${r3(n)}`;
  }
}
go.addEventListener('click', render);
document.getElementById('th-n').addEventListener('keypress', e=>{ if(e.key==='Enter') render(); });
render();

