function powers(k,lim){
  const arr=[0]; for(let x=1; ;x++){ const v=Math.pow(x,k); if(v>lim) break; arr.push(v); } return arr;
}
function decompose(n, k, s){
  // greedy then backtracking: find s k-th powers summing to n
  const P = powers(k, n);
  const found = [];
  function go(rem, left, start){
    if(left===0) return rem===0;
    if(rem<0) return false;
    for(let i=P.length-1;i>=0;i--){
      const p = P[i];
      if(p>rem) continue;
