    const alpha = i/(NSAMP-1);
    let re=0, im=0;
    for(let n=1; n<=M; n++){
      const theta = 2*Math.PI * alpha * Math.pow(n,k);
      re += Math.cos(theta);
      im += Math.sin(theta);
    }
