nEl.addEventListener('input', update);
update();

// rational arithmetic (BigInt numerator/denominator) for exact Bernoulli numbers
function gcd(a,b){ a=a<0n?-a:a; b=b<0n?-b:b; while(b){ [a,b]=[b,a%b]; } return a; }
function rat(n,d=1n){ if(typeof n==='number') n=BigInt(n); if(typeof d==='number') d=BigInt(d);
  if(d<0n){ n=-n; d=-d; } const g=gcd(n<0n?-n:n,d); return [n/g,d/g]; }
function radd(a,b){ return rat(a[0]*b[1]+b[0]*a[1], a[1]*b[1]); }
function rsub(a,b){ return rat(a[0]*b[1]-b[0]*a[1], a[1]*b[1]); }
function rmul(a,b){ return rat(a[0]*b[0], a[1]*b[1]); }
function rdiv(a,b){ return rat(a[0]*b[1], a[1]*b[0]); }
function rneg(a){ return [-a[0], a[1]]; }
function rnum(a){ return Number(a[0])/Number(a[1]); }
function rstr(a){ if(a[1]===1n) return a[0].toString(); return a[0].toString()+'/'+a[1].toString(); }
function fact(n){ let r=1n; for(let i=2n;i<=BigInt(n);i++) r*=i; return r; }
function binom(n,k){ return rat(fact(n)/(fact(k)*fact(n-k)), 1n); }

// Bernoulli via Akiyama–Tanigawa recurrence (convention B1 = -1/2)
const BCACHE = [rat(1n,1n)];
function B(n){
  while(BCACHE.length <= n){
    const m = BCACHE.length;
    // row-by-row: A[0][j] = 1/(j+1); A[i][j] = (i)*(A[i-1][j] - A[i-1][j+1])
    const N = m+1;
    let A = Array.from({length:N},(_,j)=>rat(1n, BigInt(j+1)));
    for(let i=1;i<=m;i++){
      const next = [];
      for(let j=0;j<N-i;j++){
        next.push( rmul( rat(BigInt(i),1n), rsub(A[j], A[j+1]) ) );
      }
      A = next;
    }
    BCACHE.push(A[0]);
  }
  return BCACHE[n];
}

// Faulhaber coefficients: S_m(n) = sum_{j=0..m} c_j n^{m+1-j}
// with c_j = binom(m+1,j) B_j / (m+1). Convention: B_1 = -1/2 (the "modern" one)
// which is compatible with the standard formula.
function faulCoeffs(m){
  const out = [];
  const mp1 = rat(BigInt(m+1),1n);
  for(let j=0;j<=m;j++){
    const c = rdiv( rmul(binom(m+1,j), B(j)), mp1 );
    out.push(c); // coefficient of n^{m+1-j}
  }
  return out;
}
// evaluate polynomial with rational coeffs (descending powers) at integer n (BigInt) -> rational
function evalPoly(coeffs, m, n){
  let acc = rat(0n,1n);
  for(let j=0;j<=m;j++){
    const pw = rat( BigInt(n) ** BigInt(m+1-j), 1n );
    acc = radd(acc, rmul(coeffs[j], pw));
  }
  return acc;
}
// float-valued evaluation for smooth curve drawing (no BigInt)
function evalPolyFloat(coeffs, m, x){
  let acc = 0;
  for(let j=0;j<=m;j++){
    acc += rnum(coeffs[j]) * Math.pow(x, m+1-j);
  }
  return acc;
}
function directSum(m, n){
  let s = 0n;
  for(let k=1n;k<=BigInt(n);k++){
    let p = 1n; for(let i=0;i<m;i++) p *= k;
    s += p;
  }
  return rat(s,1n);
}
function formatPoly(coeffs, m){
  // pretty-print in the variable n
  let parts = [];
  for(let j=0;j<=m;j++){
    const c = coeffs[j];
    if(c[0]===0n) continue;
    const deg = m+1-j;
    const sign = c[0] < 0n ? ' − ' : (parts.length? ' + ' : '');
    const abs = [c[0]<0n?-c[0]:c[0], c[1]];
    let coefStr = abs[1]===1n && abs[0]===1n ? '' : (abs[1]===1n? abs[0].toString() : abs[0].toString()+'/'+abs[1].toString());
    if(coefStr && deg>0) coefStr += '·';
    let nPart = '';
    if(deg===0) nPart = (coefStr? '' : '1');
    else if(deg===1) nPart = 'n';
    else nPart = 'n^'+deg;
    parts.push(sign + coefStr + nPart);
  }
  if(parts.length===0) return '0';
  return parts.join('');
}

