function zetaPartial(s, N){
  let s2 = 0;
  for(let k=1;k<=N;k++) s2 += 1/Math.pow(k,s);
  return s2;
}

const nEl=$('#z-n'), nLbl=$('#z-n-lbl'), out=$('#z-out');
function update(){
