// Lanczos approximation for Γ(s) on the real axis (good to ~1e-10)
const g=7;
const CC=[0.99999999999980993,676.5203681218851,-1259.1392167224028,771.32342877765313,
  -176.61502916214059,12.507343278686905,-0.13857109526572012,9.9843695780195716e-6,1.5056327351493116e-7];
function gamma(z){
  if(z < 0.5){ return Math.PI / (Math.sin(Math.PI*z) * gamma(1-z)); }
  z -= 1;
  let x = CC[0];
  for(let i=1;i<g+2;i++) x += CC[i]/(z+i);
  const t = z + g + 0.5;
  return Math.sqrt(2*Math.PI) * Math.pow(t, z+0.5) * Math.exp(-t) * x;
}
function zetaNumeric(s){
  // very hacky: high-N partial sum; fine for s ≥ 2 and s small-negative (via reflection)
  if(s > 1.5){
    let sum=0;
    for(let k=1;k<=100000;k++) sum += 1/Math.pow(k,s);
    return sum;
  }
  // reflection ζ(s) = 2(2π)^{s-1} sin(πs/2) Γ(1-s) ζ(1-s)
  const u = 1-s;
  let sumu=0;
  for(let k=1;k<=100000;k++) sumu += 1/Math.pow(k,u);
  return 2 * Math.pow(2*Math.PI, s-1) * Math.sin(Math.PI*s/2) * gamma(1-s) * sumu;
}
function xi(s){ return Math.pow(Math.PI, -s/2) * gamma(s/2) * zetaNumeric(s); }

