// Lanczos approximation for Γ(s) on the real axis (good to ~1e-10)
const g=7;
const CC=[0.99999999999980993,676.5203681218851,-1259.1392167224028,771.32342877765313,
  -176.61502916214059,12.507343278686905,-0.13857109526572012,9.9843695780195716e-6,1.5056327351493116e-7];
function gamma(z){
  if(z < 0.5){ return Math.PI / (Math.sin(Math.PI*z) * gamma(1-z)); }
  z -= 1;
  let x = CC[0];
  for(let i=1;i<g+2;i++) x += CC[i]/(z+i);
  const t = z + g + 0.5;
  return Math.sqrt(2*Math.PI) * Math.pow(t, z+0.5) * Math.exp(-t) * x;
}
function zetaNumeric(s){
  // very hacky: high-N partial sum; fine for s ≥ 2 and s small-negative (via reflection)
  if(s > 1.5){
    let sum=0;
    for(let k=1;k<=100000;k++) sum += 1/Math.pow(k,s);
    return sum;
  }
  // reflection ζ(s) = 2(2π)^{s-1} sin(πs/2) Γ(1-s) ζ(1-s)
  const u = 1-s;
  let sumu=0;
  for(let k=1;k<=100000;k++) sumu += 1/Math.pow(k,u);
  return 2 * Math.pow(2*Math.PI, s-1) * Math.sin(Math.PI*s/2) * gamma(1-s) * sumu;
}
function xi(s){ return Math.pow(Math.PI, -s/2) * gamma(s/2) * zetaNumeric(s); }

const sEl=$('#fe-s'), sLbl=$('#fe-s-lbl'), out=$('#fe-out'), svg=$('#fe-svg');
function update(){
  const s = parseFloat(sEl.value);
  sLbl.textContent = 's = '+s;
  const xs = xi(s), xb = xi(1-s);
  const z_s = zetaNumeric(s), z_b = zetaNumeric(1-s);
  out.textContent =
    `ζ(${s}) ≈ ${z_s.toExponential(6)}\n`+
    `ζ(${1-s}) ≈ ${z_b.toExponential(6)}\n\n`+
    `ξ(${s}) = π^{-s/2} Γ(s/2) ζ(s) ≈ ${xs.toExponential(6)}\n`+
    `ξ(${1-s}) = π^{-(1-s)/2} Γ((1-s)/2) ζ(1-s) ≈ ${xb.toExponential(6)}\n\n`+
    `|ξ(s) − ξ(1−s)| = ${Math.abs(xs-xb).toExponential(3)}   (should be ≈ 0)`;
  // bar chart of xi(s), xi(1-s) and difference
  svg.innerHTML='';
  const labs=['ξ(1−s)','ξ(s)','|Δ|'];
  const vals=[Math.abs(xb), Math.abs(xs), Math.abs(xs-xb)];
  const cols=['var(--blue)','var(--yellow)','var(--pink)'];
  const logVals = vals.map(v=>Math.log10(Math.max(v,1e-30)));
  const yMin=-30, yMax=2;
  const H=160, pad=18, baseY=H-28;
  const W=620;
  for(let i=0;i<3;i++){
    const x = 140 + i*140;
    const h = Math.max(2, (logVals[i]-yMin)/(yMax-yMin) * (baseY-12));
    svg.appendChild(SVG('rect',{x:x-36,y:baseY-h,width:72,height:h,fill:cols[i],opacity:0.8}));
    const t1 = SVG('text',{x:x,y:baseY+14,'text-anchor':'middle','font-size':11,fill:'var(--ink)'});
    t1.textContent = labs[i]; svg.appendChild(t1);
    const t2 = SVG('text',{x:x,y:baseY-h-4,'text-anchor':'middle','font-size':10,fill:'var(--mute)'});
    t2.textContent = vals[i].toExponential(2); svg.appendChild(t2);
  }
  svg.appendChild(SVG('line',{x1:40,y1:baseY,x2:W-20,y2:baseY,stroke:'var(--line)'}));
}
