function gcd(a,b){ a=a<0n?-a:a; b=b<0n?-b:b; while(b){ [a,b]=[b,a%b]; } return a; }
function rat(n,d=1n){ if(typeof n==='number') n=BigInt(n); if(typeof d==='number') d=BigInt(d);
  if(d<0n){ n=-n; d=-d; } const g=gcd(n<0n?-n:n,d); return [n/g,d/g]; }
function radd(a,b){ return rat(a[0]*b[1]+b[0]*a[1], a[1]*b[1]); }
function rsub(a,b){ return rat(a[0]*b[1]-b[0]*a[1], a[1]*b[1]); }
function rmul(a,b){ return rat(a[0]*b[0], a[1]*b[1]); }
function rnum(a){ return Number(a[0])/Number(a[1]); }
function fact(n){ let r=1n; for(let i=2n;i<=BigInt(n);i++) r*=i; return r; }
const BCACHE=[rat(1n,1n)];
function B(n){
  while(BCACHE.length <= n){
    const m = BCACHE.length;
    const N2 = m+1;
    let A = Array.from({length:N2},(_,j)=>rat(1n, BigInt(j+1)));
    for(let i=1;i<=m;i++){
      const next=[];
      for(let j=0;j<N2-i;j++){
        next.push( rmul(rat(BigInt(i),1n), rsub(A[j], A[j+1])) );
      }
      A = next;
    }
    BCACHE.push(A[0]);
  }
  return BCACHE[n];
}

function naivePartial(s, N){ let x=0; for(let k=1;k<=N;k++) x += 1/Math.pow(k,s); return x; }
// Euler-Maclaurin: split at N. Use partial 1..N-1 + tail via integral + endpoint + corrections
function emZeta(s, N, K){
  let x = 0;
  for(let k=1;k<=N-1;k++) x += 1/Math.pow(k,s);
  x += Math.pow(N,1-s)/(s-1);
  x += 0.5 / Math.pow(N,s);
  // sum_{k=1..K} B_{2k}/(2k)! * product_{j=0..2k-2}(s+j) / N^{s+2k-1}
  for(let k=1;k<=K;k++){
    let prod = 1;
    for(let j=0;j<=2*k-2;j++) prod *= (s + j);
    const b = rnum(B(2*k));
    const fk = Number(fact(2*k));
    x += b / fk * prod / Math.pow(N, s+2*k-1);
  }
  return x;
}
// "true" value via huge partial sum
function zetaTrue(s){ let x=0; for(let k=1;k<=500000;k++) x += 1/Math.pow(k,s); return x; }

const sEl=$('#a-s'), sLbl=$('#a-s-lbl'), NEl=$('#a-N'), NLbl=$('#a-N-lbl'),
